	@Test
	void resolvesUrlParametersRequestParametersCookiesAndDefaults() throws Exception {
		MockHttpServletRequest request = new MockHttpServletRequest("GET", "/repositories");
		request.setScheme("http");
		request.setServerName("localhost");
		request.setRequestURI("/repositories;explicit=fromUrl&encoded=alpha+beta&type=export&limit=20");
		request.addParameter("repeat", "first", "last");
		request.addParameter("empty", "");
		request.addParameter("nullValue", "null");
		request.setCookies(new Cookie("cookieOnly", "cookieValue"));

		WorkbenchRequest wrapped = new WorkbenchRequest(null, request,
				Map.of("defaultOnly", "defaultValue", "defaultInt", "12"));

		assertThat(wrapped.getParameter("explicit")).isEqualTo("fromUrl");
		assertThat(wrapped.getParameterValues("explicit")).containsExactly("fromUrl");
		assertThat(wrapped.getParameter("encoded")).isEqualTo("alpha beta");
		assertThat(wrapped.getTypeParameter()).isEqualTo("export");
		assertThat(wrapped.getParameter("repeat")).isEqualTo("last");
		assertThat(wrapped.getParameterValues("repeat")).containsExactly("first", "last");
		assertThat(wrapped.getParameter("cookieOnly")).isEqualTo("cookieValue");
		assertThat(wrapped.getParameter("defaultOnly")).isEqualTo("defaultValue");
		assertThat(wrapped.getInt("limit")).isEqualTo(20);
		assertThat(wrapped.getInt("defaultInt")).isEqualTo(12);
		assertThat(wrapped.isParameterPresent("explicit")).isTrue();
		assertThat(wrapped.isParameterPresent("empty")).isFalse();
		assertThat(wrapped.getValue("nullValue")).isNull();
		assertThat(wrapped.getSingleParameterMap()).containsEntry("explicit", "fromUrl")
				.containsEntry("repeat", "last")
				.containsEntry("encoded", "alpha beta")
				.doesNotContainKey("empty");
	}

	@Test
	void parsesMultipartParametersAndUploadedContent() throws Exception {
		HttpServletRequest request = mock(HttpServletRequest.class);
		Part title = mock(Part.class);
		Part content = mock(Part.class);
		when(request.getMethod()).thenReturn("POST");
		when(request.getContentType()).thenReturn("multipart/form-data; boundary=test");
		when(request.getRequestURL()).thenReturn(new StringBuffer("http://localhost/upload"));
		when(request.getParts()).thenReturn(java.util.List.of(title, content));
		when(request.getParameterMap()).thenReturn(Collections.emptyMap());
		when(title.getName()).thenReturn("title");
		when(title.getInputStream())
				.thenReturn(new ByteArrayInputStream("line-one\nline-two".getBytes(StandardCharsets.UTF_8)));
		when(content.getName()).thenReturn("content");
		when(content.getInputStream()).thenReturn(new ByteArrayInputStream("payload".getBytes(StandardCharsets.UTF_8)));
		when(content.getSubmittedFileName()).thenReturn("upload.ttl");

		WorkbenchRequest wrapped = new WorkbenchRequest(null, request, Map.of());

		assertThat(wrapped.getParameter("title")).isEqualTo("line-one");
		assertThat(wrapped.getParameterValues("title")).containsExactly("line-one");
		assertThat(wrapped.getContentFileName()).isEqualTo("upload.ttl");
		assertThat(new String(wrapped.getContentParameter().readAllBytes(), StandardCharsets.UTF_8))
				.isEqualTo("payload");
		assertThat(wrapped.getSingleParameterMap()).containsEntry("title", "line-one");
	}

	@Test
	void parsesTypedParametersAndRejectsInvalidValues() throws Exception {
		MockHttpServletRequest request = new MockHttpServletRequest("GET", "/values");
		request.addParameter("intValue", "4");
		request.addParameter("badInt", "four");
		request.addParameter("iri", "<urn:test:iri>");
		request.addParameter("bnode", "_:node1");
		request.addParameter("literal", "\"value\"");
		request.addParameter("url", "https://example.org/path");
		request.addParameter("badUrl", "://broken");

		WorkbenchRequest wrapped = new WorkbenchRequest(null, request, Map.of());

		assertThat(wrapped.getInt("intValue")).isEqualTo(4);
		assertThat(wrapped.getValue("literal").stringValue()).isEqualTo("value");
		assertThat(wrapped.getURI("iri")).isEqualTo(org.eclipse.rdf4j.model.impl.SimpleValueFactory.getInstance()
				.createIRI("urn:test:iri"));
		assertThat(wrapped.getResource("bnode")).isInstanceOf(Resource.class);
		assertThat(wrapped.getUrl("url").toString()).isEqualTo("https://example.org/path");
		assertThatThrownBy(() -> wrapped.getInt("badInt")).isInstanceOf(BadRequestException.class);
		assertThatThrownBy(() -> wrapped.getUrl("badUrl")).isInstanceOf(BadRequestException.class);
		assertThatThrownBy(() -> wrapped.getResource("literal")).isInstanceOf(BadRequestException.class)
				.hasMessageContaining("Not a BNode or URI");
		assertThatThrownBy(() -> wrapped.getURI("bnode")).isInstanceOf(BadRequestException.class)
				.hasMessageContaining("Not a URI");
	}

	@Test
	void returnsZeroForMissingIntegerAndNullForBlankValues() throws Exception {
		MockHttpServletRequest request = new MockHttpServletRequest("GET", "/empty");
		request.addParameter("blank", " ");
		request.addParameter("emptyNumber", "");

		WorkbenchRequest wrapped = new WorkbenchRequest(null, request, Map.of());

		assertThat(wrapped.getInt("missing")).isZero();
		assertThat(wrapped.getInt("emptyNumber")).isZero();
		assertThat(wrapped.getValue("blank")).isNull();
	}

	@Test
	void postWithoutMultipartContentLeavesRequestParametersInControl() throws Exception {
		MockHttpServletRequest request = new MockHttpServletRequest("POST", "/plain");
		request.addParameter("present", "first", "final");
		request.addParameter("emptyTail", "value", "");

		WorkbenchRequest wrapped = new WorkbenchRequest(null, request, null);

		assertThat(wrapped.getParameter("present")).isEqualTo("final");
		assertThat(wrapped.getParameter("missing")).isNull();
		assertThat(wrapped.getParameterValues("missing")).isNull();
		assertThat(wrapped.isParameterPresent("present")).isTrue();
		assertThat(wrapped.isParameterPresent("emptyTail")).isFalse();
		assertThat(wrapped.getResource("missing")).isNull();
		assertThat(wrapped.getURI("missing")).isNull();
		assertThat(wrapped.getSingleParameterMap()).containsEntry("present", "final")
				.doesNotContainKey("emptyTail");
	}

	@Test
	void repositoryAwareRequestsCoverPlainPostAndBlankUrlParameters() throws Exception {
		org.eclipse.rdf4j.repository.Repository repository = mock(org.eclipse.rdf4j.repository.Repository.class);
		when(repository.getValueFactory()).thenReturn(org.eclipse.rdf4j.model.impl.SimpleValueFactory.getInstance());

		HttpServletRequest postRequest = mock(HttpServletRequest.class);
		when(postRequest.getMethod()).thenReturn("POST");
		when(postRequest.getContentType()).thenReturn("text/plain");
		when(postRequest.getRequestURL()).thenReturn(new StringBuffer("http://localhost/plain"));
		when(postRequest.getParameter("emptyNumber")).thenReturn("");
		when(postRequest.getQueryString()).thenReturn(null);

		WorkbenchRequest plainPost = new WorkbenchRequest(repository, postRequest, Map.of());
		assertThat(plainPost.getInt("emptyNumber")).isZero();

		MockHttpServletRequest urlRequest = new MockHttpServletRequest("GET", "/repositories");
		urlRequest.setScheme("http");
		urlRequest.setServerName("localhost");
		urlRequest.setRequestURI("/repositories;blank=&filled=value");

		WorkbenchRequest fromUrl = new WorkbenchRequest(repository, urlRequest, Map.of());
		assertThat(fromUrl.getParameter("blank")).isEmpty();
		assertThat(fromUrl.isParameterPresent("blank")).isFalse();
		assertThat(fromUrl.isParameterPresent("filled")).isTrue();
	}

